#include <spdlog/spdlog.h>
#include <nlohmann/json.hpp>

namespace RawrXD {

enum class TokenError {
    Success = 0,
    EncodingFailed,
    DecodingFailed,
    VocabularyNotLoaded,
    TokenNotFound,
    InvalidTokenId,
    MergeRulesNotLoaded,
    TokenizationFailed,
    UnicodeConversionFailed,
    FileReadFailed,
    InvalidFormat,
    OutOfMemory
};

enum class TokenizationStrategy {
    BPE,
    WordPiece,
    SentencePiece,
    Unigram
};

struct TokenizationConfig {
    TokenizationStrategy strategy = TokenizationStrategy::BPE;
    std::string vocabPath;
    std::string mergesPath;
    std::string modelPath;
    bool enableCache = true;
    size_t maxCacheSize = 10000;
    bool handleUnicode = true;
    bool addPrefixSpace = true;
    bool addSpecialTokens = true;
};

struct TokenInfo {
    int id;
    std::string text;
    float score;
    std::string type; // "special", "word", "subword", "punctuation"
};

class TokenGenerator {
public:
    TokenGenerator();
    explicit TokenGenerator(const TokenizationConfig& config);
    ~TokenGenerator();
    
    // Non-copyable
    TokenGenerator(const TokenGenerator&) = delete;
    TokenGenerator& operator=(const TokenGenerator&) = delete;
    
    // Movable
    TokenGenerator(TokenGenerator&&) noexcept;
    TokenGenerator& operator=(TokenGenerator&&) noexcept;
    
    // Real tokenization
    std::expected<std::vector<int>, TokenError> encode(const std::string& text);
    std::expected<std::string, TokenError> decode(const std::vector<int>& tokens);
    
    // Real batch processing
    std::expected<std::vector<std::vector<int>>, TokenError> encodeBatch(
        const std::vector<std::string>& texts
    );
    
    std::expected<std::vector<std::string>, TokenError> decodeBatch(
        const std::vector<std::vector<int>>& tokenBatches
    );
    
    // Real vocabulary management
    std::expected<void, TokenError> loadVocabulary(const std::string& vocabPath);
    std::expected<void, TokenError> loadVocabularyFromModel(
        const std::string& modelPath
    );
    
    // Real merge rules loading
    std::expected<void, TokenError> loadMergeRules(const std::string& mergesPath);
    
    // Real token operations
    std::expected<int, TokenError> getTokenId(const std::string& token);
    std::expected<std::string, TokenError> getTokenString(int tokenId);
    
    // Special tokens
    int getBosToken() const { return m_bosToken; }
    int getEosToken() const { return m_eosToken; }
    int getPadToken() const { return m_padToken; }
    int getUnkToken() const { return m_unkToken; }
    int getMaskToken() const { return m_maskToken; }
    
    // Real token properties
    std::expected<TokenInfo, TokenError> getTokenInfo(int tokenId);
    std::expected<TokenInfo, TokenError> getTokenInfo(const std::string& token);
    
    // Real caching
    void clearCache();
    size_t getCacheSize() const;
    size_t getCacheHits() const { return m_cacheHits.load(); }
    size_t getCacheMisses() const { return m_cacheMisses.load(); }
    
    // Status
    size_t getVocabSize() const { return m_vocab.size(); }
    size_t getMergeRulesSize() const { return m_mergeRules.size(); }
    bool isVocabLoaded() const { return !m_vocab.empty(); }
    bool isMergeRulesLoaded() const { return !m_mergeRules.empty(); }
    json getStatus() const;
    
    // Configuration
    void setConfig(const TokenizationConfig& config);
    const TokenizationConfig& getConfig() const { return m_config; }
    
private:
    TokenizationConfig m_config;
    std::atomic<bool> m_initialized{false};
    mutable std::mutex m_mutex;
    
    // Real vocabulary
    std::unordered_map<std::string, int> m_vocab;
    std::unordered_map<int, std::string> m_idToToken;
    std::unordered_map<int, TokenInfo> m_tokenInfo;
    
    // Real BPE merge rules
    std::vector<std::pair<std::string, std::string>> m_mergeRules;
    std::unordered_map<std::pair<std::string, std::string>, int> m_mergeRank;
    
    // Real cache
    struct CacheEntry {
        std::vector<int> tokens;
        std::chrono::steady_clock::time_point timestamp;
    };
    
    mutable std::mutex m_cacheMutex;
    std::unordered_map<std::string, CacheEntry> m_encodeCache;
    std::unordered_map<std::string, CacheEntry> m_decodeCache;
    std::atomic<size_t> m_cacheHits{0};
    std::atomic<size_t> m_cacheMisses{0};
    std::atomic<size_t> m_cacheSize{0};
    
    // Special tokens
    int m_bosToken = 1;
    int m_eosToken = 2;
    int m_padToken = 0;
    int m_unkToken = 3;
    int m_maskToken = 4;
    
    // Real implementation methods
    std::expected<std::vector<int>, TokenError> bpeEncode(const std::string& text);
    std::expected<std::string, TokenError> bpeDecode(const std::vector<int>& tokens);
    
    std::expected<std::vector<int>, TokenError> wordpieceEncode(const std::string& text);
    std::expected<std::string, TokenError> wordpieceDecode(const std::vector<int>& tokens);
    
    std::expected<std::vector<int>, TokenError> sentencepieceEncode(const std::string& text);
    std::expected<std::string, TokenError> sentencepieceDecode(const std::vector<int>& tokens);
    
    // Real Unicode handling
    std::expected<std::wstring, TokenError> utf8ToWide(const std::string& utf8);
    std::expected<std::string, TokenError> wideToUtf8(const std::wstring& wide);
    
    // Real token validation
    bool isValidTokenId(int tokenId) const;
    bool isValidToken(const std::string& token) const;
    
    // Real caching
    std::expected<std::vector<int>, TokenError> getFromCache(
        const std::string& text,
        bool isEncode
    );
    
    void addToCache(
        const std::string& text,
        const std::vector<int>& tokens,
        bool isEncode
    );
    
    void evictCacheIfNeeded();
    
    // Real merge rule application
    std::expected<std::vector<std::string>, TokenError> applyBPERules(
        const std::vector<std::string>& tokens
    );
    
    // Real token type detection
    std::string detectTokenType(const std::string& token) const;
    
    // Real logging
    void logTokenization(const std::string& text, const std::vector<int>& tokens);
    void logError(const std::string& message, TokenError error);
    
    // Performance metrics
    std::atomic<size_t> m_totalEncodings{0};
    std::atomic<size_t> m_totalDecodings{0};
    std::atomic<std::chrono::milliseconds> m_totalEncodingTime{0};
    std::atomic<std::chrono::milliseconds> m_totalDecodingTime{0};
};

} // namespace RawrXD
