### `token_generator.cpp` - Complete Production Implementation
```cpp
#include "token_generator.h"
#include <fstream>
#include <sstream>
#include <algorithm>
#include <chrono>
#include <codecvt>
#include <locale>
#include <cwctype>
#include <spdlog/spdlog.h>
#include <nlohmann/json.hpp>

namespace RawrXD {

TokenGenerator::TokenGenerator() : m_config(TokenizationConfig()) {
    initialize();
}

TokenGenerator::TokenGenerator(const TokenizationConfig& config) : m_config(config) {
    initialize();
}

TokenGenerator::~TokenGenerator() {
    // Cleanup resources
    clearCache();
}

TokenGenerator::TokenGenerator(TokenGenerator&& other) noexcept
    : m_config(std::move(other.m_config)),
      m_initialized(other.m_initialized.load()),
      m_vocab(std::move(other.m_vocab)),
      m_idToToken(std::move(other.m_idToToken)),
      m_tokenInfo(std::move(other.m_tokenInfo)),
      m_mergeRules(std::move(other.m_mergeRules)),
      m_mergeRank(std::move(other.m_mergeRank)),
      m_bosToken(other.m_bosToken),
      m_eosToken(other.m_eosToken),
      m_padToken(other.m_padToken),
      m_unkToken(other.m_unkToken),
      m_maskToken(other.m_maskToken),
      m_cacheHits(other.m_cacheHits.load()),
      m_cacheMisses(other.m_cacheMisses.load()),
      m_cacheSize(other.m_cacheSize.load()),
      m_totalEncodings(other.m_totalEncodings.load()),
      m_totalDecodings(other.m_totalDecodings.load()),
      m_totalEncodingTime(other.m_totalEncodingTime.load()),
      m_totalDecodingTime(other.m_totalDecodingTime.load()) {
    
    // Move cache
    std::lock_guard lock(other.m_cacheMutex);
    m_encodeCache = std::move(other.m_encodeCache);
    m_decodeCache = std::move(other.m_decodeCache);
}

TokenGenerator& TokenGenerator::operator=(TokenGenerator&& other) noexcept {
    if (this != &other) {
        m_config = std::move(other.m_config);
        m_initialized = other.m_initialized.load();
        m_vocab = std::move(other.m_vocab);
        m_idToToken = std::move(other.m_idToToken);
        m_tokenInfo = std::move(other.m_tokenInfo);
        m_mergeRules = std::move(other.m_mergeRules);
        m_mergeRank = std::move(other.m_mergeRank);
        m_bosToken = other.m_bosToken;
        m_eosToken = other.m_eosToken;
        m_padToken = other.m_padToken;
        m_unkToken = other.m_unkToken;
        m_maskToken = other.m_maskToken;
        m_cacheHits = other.m_cacheHits.load();
        m_cacheMisses = other.m_cacheMisses.load();
        m_cacheSize = other.m_cacheSize.load();
        m_totalEncodings = other.m_totalEncodings.load();
        m_totalDecodings = other.m_totalDecodings.load();
        m_totalEncodingTime = other.m_totalEncodingTime.load();
        m_totalDecodingTime = other.m_totalDecodingTime.load();
        
        // Move cache
        std::lock_guard lock(other.m_cacheMutex);
        m_encodeCache = std::move(other.m_encodeCache);
        m_decodeCache = std::move(other.m_decodeCache);
    }
    return *this;
}

void TokenGenerator::initialize() {
    std::lock_guard lock(m_mutex);
    
    // Load default special tokens
    m_vocab["<pad>"] = m_padToken;
    m_vocab["<s>"] = m_bosToken;
    m_vocab["</s>"] = m_eosToken;
    m_vocab["<unk>"] = m_unkToken;
    m_vocab["<mask>"] = m_maskToken;
    
    // Load vocabulary if path provided
    if (!m_config.vocabPath.empty()) {
        auto result = loadVocabulary(m_config.vocabPath);
        if (!result) {
            spdlog::warn("Failed to load vocabulary from {}: {}", 
                        m_config.vocabPath, static_cast<int>(result.error()));
        }
    }
    
    // Load merge rules if path provided
    if (!m_config.mergesPath.empty()) {
        auto result = loadMergeRules(m_config.mergesPath);
        if (!result) {
            spdlog::warn("Failed to load merge rules from {}: {}", 
                        m_config.mergesPath, static_cast<int>(result.error()));
        }
    }
    
    // Load from model if path provided
    if (!m_config.modelPath.empty()) {
        auto result = loadVocabularyFromModel(m_config.modelPath);
        if (!result) {
            spdlog::warn("Failed to load vocabulary from model {}: {}", 
                        m_config.modelPath, static_cast<int>(result.error()));
        }
    }
    
    // Build reverse mapping
    for (const auto& [token, id] : m_vocab) {
        m_idToToken[id] = token;
    }
    
    m_initialized = true;
    spdlog::debug("TokenGenerator initialized with {} tokens", m_vocab.size());
}

std::expected<std::vector<int>, TokenError> TokenGenerator::encode(const std::string& text) {
    if (!m_initialized.load()) {
        return std::unexpected(TokenError::TokenizationFailed);
    }
    
    if (text.empty()) {
        return std::vector<int>();
    }
    
    // Check cache first
    if (m_config.enableCache) {
        auto cacheResult = getFromCache(text, true);
        if (cacheResult) {
            m_cacheHits.fetch_add(1);
            return cacheResult.value();
        }
        m_cacheMisses.fetch_add(1);
    }
    
    auto startTime = std::chrono::steady_clock::now();
    
    // Real tokenization based on strategy
    std::vector<int> tokens;
    TokenError error = TokenError::Success;
    
    switch (m_config.strategy) {
        case TokenizationStrategy::BPE:
            {
                auto result = bpeEncode(text);
                if (!result) {
                    return result;
                }
                tokens = result.value();
            }
            break;
            
        case TokenizationStrategy::WordPiece:
            {
                auto result = wordpieceEncode(text);
                if (!result) {
                    return result;
                }
                tokens = result.value();
            }
            break;
            
        case TokenizationStrategy::SentencePiece:
            {
                auto result = sentencepieceEncode(text);
                if (!result) {
                    return result;
                }
                tokens = result.value();
            }
            break;
            
        case TokenizationStrategy::Unigram:
            {
                // Fallback to BPE for unigram
                auto result = bpeEncode(text);
                if (!result) {
                    return result;
                }
                tokens = result.value();
            }
            break;
    }
    
    // Add special tokens if configured
    if (m_config.addSpecialTokens) {
        tokens.insert(tokens.begin(), m_bosToken);
        tokens.push_back(m_eosToken);
    }
    
    // Cache result
    if (m_config.enableCache) {
        addToCache(text, tokens, true);
    }
    
    auto endTime = std::chrono::steady_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::milliseconds>(endTime - startTime);
    m_totalEncodingTime.fetch_add(duration);
    m_totalEncodings.fetch_add(1);
    
    logTokenization(text, tokens);
    
    return tokens;
}

std::expected<std::string, TokenError> TokenGenerator::decode(const std::vector<int>& tokens) {
    if (!m_initialized.load()) {
        return std::unexpected(TokenError::TokenizationFailed);
    }
    
    if (tokens.empty()) {
        return std::string();
    }
    
    // Create cache key
    std::string cacheKey;
    for (int token : tokens) {
        cacheKey += std::to_string(token) + ",";
    }
    
    // Check cache
    if (m_config.enableCache) {
        auto cacheResult = getFromCache(cacheKey, false);
        if (cacheResult) {
            m_cacheHits.fetch_add(1);
            return cacheResult.value();
        }
        m_cacheMisses.fetch_add(1);
    }
    
    auto startTime = std::chrono::steady_clock::now();
    
    // Real decoding based on strategy
    std::string text;
    
    switch (m_config.strategy) {
        case TokenizationStrategy::BPE:
            {
                auto result = bpeDecode(tokens);
                if (!result) {
                    return result;
                }
                text = result.value();
            }
            break;
            
        case TokenizationStrategy::WordPiece:
            {
                auto result = wordpieceDecode(tokens);
                if (!result) {
                    return result;
                }
                text = result.value();
            }
            break;
            
        case TokenizationStrategy::SentencePiece:
            {
                auto result = sentencepieceDecode(tokens);
                if (!result) {
                    return result;
                }
                text = result.value();
            }
            break;
            
        case TokenizationStrategy::Unigram:
            {
                // Fallback to BPE
                auto result = bpeDecode(tokens);
                if (!result) {
                    return result;
                }
                text = result.value();
            }
            break;
    }
    
    // Cache result
    if (m_config.enableCache) {
        addToCache(cacheKey, std::vector<int>(text.begin(), text.end()), false);
    }
    
    auto endTime = std::chrono::steady_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::milliseconds>(endTime - startTime);
    m_totalDecodingTime.fetch_add(duration);
    m_totalDecodings.fetch_add(1);
    
    return text;
}

std::expected<std::vector<int>, TokenError> TokenGenerator::bpeEncode(const std::string& text) {
    if (m_vocab.empty()) {
        return std::unexpected(TokenError::VocabularyNotLoaded);
    }
    
    // Handle Unicode if enabled
    std::string processedText = text;
    if (m_config.handleUnicode) {
        // Convert to lowercase and normalize
        std::transform(processedText.begin(), processedText.end(), processedText.begin(),
                      [](unsigned char c) { return std::tolower(c); });
    }
    
    // Add prefix space if configured
    if (m_config.addPrefixSpace && !processedText.empty() && processedText[0] != ' ') {
        processedText = " " + processedText;
    }
    
    // Split into words
    std::vector<std::string> words;
    std::istringstream stream(processedText);
    std::string word;
    
    while (stream >> word) {
        words.push_back(word);
    }
    
    if (words.empty()) {
        return std::vector<int>();
    }
    
    // Apply BPE to each word
    std::vector<int> tokens;
    
    for (const auto& word : words) {
        // Start with character-level tokens
        std::vector<std::string> wordTokens;
        for (char c : word) {
            wordTokens.push_back(std::string(1, c));
        }
        
        // Apply merge rules if available
        if (!m_mergeRules.empty()) {
            auto mergedResult = applyBPERules(wordTokens);
            if (!mergedResult) {
                return std::unexpected(mergedResult.error());
            }
            wordTokens = mergedResult.value();
        }
        
        // Convert to IDs
        for (const auto& token : wordTokens) {
            auto idResult = findToken(token);
            if (idResult) {
                tokens.push_back(idResult.value());
            } else {
                // Try subword tokens
                bool found = false;
                
                // Check for prefix token
                std::string prefixToken = "▁" + token;
                auto prefixResult = findToken(prefixToken);
                if (prefixResult) {
                    tokens.push_back(prefixResult.value());
                    found = true;
                } else {
                    // Check for suffix token
                    std::string suffixToken = token + "</w>";
                    auto suffixResult = findToken(suffixToken);
                    if (suffixResult) {
                        tokens.push_back(suffixResult.value());
                        found = true;
                    }
                }
                
                if (!found) {
                    tokens.push_back(m_unkToken);
                }
            }
        }
        
        // Add space token if not last word
        if (&word != &words.back()) {
            auto spaceResult = findToken(" ");
            if (spaceResult) {
                tokens.push_back(spaceResult.value());
            }
        }
    }
    
    return tokens;
}

std::expected<std::vector<std::string>, TokenError> TokenGenerator::applyBPERules(
    const std::vector<std::string>& tokens
) {
    if (m_mergeRules.empty()) {
        return tokens;
    }
    
    std::vector<std::string> result = tokens;
    bool changed = true;
    int iterations = 0;
    const int MAX_ITERATIONS = 100;
    
    while (changed && iterations < MAX_ITERATIONS) {
        changed = false;
        iterations++;
        
        // Find best merge
        std::pair<std::string, std::string> bestMerge;
        int bestRank = -1;
        size_t bestPos = 0;
        
        for (size_t i = 0; i + 1 < result.size(); ++i) {
            auto it = m_mergeRank.find({result[i], result[i + 1]});
            if (it != m_mergeRank.end() && it->second > bestRank) {
                bestRank = it->second;
                bestMerge = {result[i], result[i + 1]};
                bestPos = i;
            }
        }
        
        // Apply merge
        if (bestRank >= 0) {
            result[bestPos] = bestMerge.first + bestMerge.second;
            result.erase(result.begin() + bestPos + 1);
            changed = true;
        }
    }
    
    if (iterations >= MAX_ITERATIONS) {
        spdlog::warn("BPE reached maximum iterations for token sequence");
    }
    
    return result;
}

std::expected<std::string, TokenError> TokenGenerator::bpeDecode(const std::vector<int>& tokens) {
    if (tokens.empty()) {
        return std::string();
    }
    
    std::string text;
    
    for (int tokenId : tokens) {
        // Skip special tokens
        if (tokenId == m_bosToken || tokenId == m_eosToken || 
            tokenId == m_padToken || tokenId == m_maskToken) {
            continue;
        }
        
        auto tokenResult = findTokenString(tokenId);
        if (tokenResult) {
            std::string token = tokenResult.value();
            
            // Handle subword tokens
            if (token.substr(0, 3) == "▁") {
                // Prefix token - add space
                if (!text.empty() && text.back() != ' ') {
                    text += ' ';
                }
                text += token.substr(3);
            } else if (token.substr(token.length() - 4) == "</w>") {
                // Suffix token - add space after
                text += token.substr(0, token.length() - 4);
                text += ' ';
            } else {
                text += token;
            }
        } else {
            // Unknown token
            text += "<unk>";
        }
    }
    
    // Clean up spaces
    // Remove multiple spaces
    size_t pos = 0;
    while ((pos = text.find("  ", pos)) != std::string::npos) {
        text.replace(pos, 2, " ");
    }
    
    // Trim leading/trailing spaces
    text.erase(0, text.find_first_not_of(" "));
    text.erase(text.find_last_not_of(" ") + 1);
    
    return text;
}

std::expected<std::vector<int>, TokenError> TokenGenerator::wordpieceEncode(const std::string& text) {
    // WordPiece tokenization (used by BERT models)
    std::vector<int> tokens;
    
    // Split into words
    std::vector<std::string> words;
    std::istringstream stream(text);
    std::string word;
    
    while (stream >> word) {
        words.push_back(word);
    }
    
    for (const auto& word : words) {
        // Try whole word first
        auto idResult = findToken(word);
        if (idResult) {
            tokens.push_back(idResult.value());
        } else {
            // WordPiece segmentation
            std::string current = word;
            bool found = false;
            
            while (!current.empty()) {
                // Try longest prefix
                std::string prefix = current;
                bool prefixFound = false;
                
                while (!prefix.empty()) {
                    auto prefixId = findToken(prefix);
                    if (prefixId) {
                        tokens.push_back(prefixId.value());
                        current = current.substr(prefix.length());
                        prefixFound = true;
                        found = true;
                        break;
                    }
                    prefix.pop_back();
                }
                
                if (!prefixFound) {
                    // No prefix found, use unknown token
                    tokens.push_back(m_unkToken);
                    break;
                }
            }
            
            if (!found) {
                tokens.push_back(m_unkToken);
            }
        }
        
        // Add space token
        if (&word != &words.back()) {
            auto spaceId = findToken(" ");
            if (spaceId) {
                tokens.push_back(spaceId.value());
            }
        }
    }
    
    return tokens;
}

std::expected<std::string, TokenError> TokenGenerator::wordpieceDecode(const std::vector<int>& tokens) {
    std::string text;
    bool isFirstToken = true;
    
    for (int tokenId : tokens) {
        // Skip special tokens
        if (tokenId == m_bosToken || tokenId == m_eosToken || 
            tokenId == m_padToken || tokenId == m_maskToken) {
            continue;
        }
        
        auto tokenResult = findTokenString(tokenId);
        if (!tokenResult) {
            text += "<unk>";
            continue;
        }
        
        std::string token = tokenResult.value();
        
        // Handle WordPiece tokens
        if (token.substr(0, 2) == "##") {
            // Subword token - no space
            text += token.substr(2);
        } else {
            // Word token - add space if not first
            if (!isFirstToken && !text.empty() && text.back() != ' ') {
                text += ' ';
            }
            text += token;
        }
        
        isFirstToken = false;
    }
    
    return text;
}

