std::expected<void, TokenError> TokenGenerator::loadVocabulary(const std::string& vocabPath) {
    std::lock_guard lock(m_mutex);
    
    if (!fs::exists(vocabPath)) {
        spdlog::error("Vocabulary file not found: {}", vocabPath);
        return std::unexpected(TokenError::FileReadFailed);
    }
    
    std::ifstream file(vocabPath);
    if (!file) {
        spdlog::error("Failed to open vocabulary file: {}", vocabPath);
        return std::unexpected(TokenError::FileReadFailed);
    }
    
    // Clear existing vocabulary
    m_vocab.clear();
    m_idToToken.clear();
    m_tokenInfo.clear();
    
    // Load special tokens first
    m_vocab["<pad>"] = m_padToken;
    m_vocab["<s>"] = m_bosToken;
    m_vocab["</s>"] = m_eosToken;
    m_vocab["<unk>"] = m_unkToken;
    m_vocab["<mask>"] = m_maskToken;
    
    // Load from file
    std::string line;
    int id = 5; // Start after special tokens
    size_t lineNumber = 0;
    
    while (std::getline(file, line)) {
        lineNumber++;
        
        // Trim whitespace
        line.erase(0, line.find_first_not_of(" \t\r\n"));
        line.erase(line.find_last_not_of(" \t\r\n") + 1);
        
        if (line.empty() || line[0] == '#') {
            continue; // Skip comments and empty lines
        }
        
        // Parse based on format
        size_t spacePos = line.find(' ');
        if (spacePos != std::string::npos) {
            // Format: "token id"
            std::string token = line.substr(0, spacePos);
            std::string idStr = line.substr(spacePos + 1);
            
            try {
                int tokenId = std::stoi(idStr);
                m_vocab[token] = tokenId;
                m_idToToken[tokenId] = token;
                
                // Store token info
                TokenInfo info;
                info.id = tokenId;
                info.text = token;
                info.type = detectTokenType(token);
                m_tokenInfo[tokenId] = info;
                
                id = std::max(id, tokenId + 1);
            } catch (const std::exception& e) {
                spdlog::warn("Invalid line {} in vocabulary file: {}", lineNumber, line);
            }
        } else {
            // Format: "token" (sequential IDs)
            m_vocab[line] = id;
            m_idToToken[id] = line;
            
            TokenInfo info;
            info.id = id;
            info.text = line;
            info.type = detectTokenType(line);
            m_tokenInfo[id] = info;
            
            id++;
        }
    }
    
    // Update special token IDs if they were in the file
    auto padIt = m_vocab.find("<pad>");
    if (padIt != m_vocab.end()) m_padToken = padIt->second;
    
    auto bosIt = m_vocab.find("<s>");
    if (bosIt != m_vocab.end()) m_bosToken = bosIt->second;
    
    auto eosIt = m_vocab.find("</s>");
    if (eosIt != m_vocab.end()) m_eosToken = eosIt->second;
    
    auto unkIt = m_vocab.find("<unk>");
    if (unkIt != m_vocab.end()) m_unkToken = unkIt->second;
    
    auto maskIt = m_vocab.find("<mask>");
    if (maskIt != m_vocab.end()) m_maskToken = maskIt->second;
    
    spdlog::info("Loaded vocabulary with {} tokens from {}", m_vocab.size(), vocabPath);
    
    // Clear cache
    clearCache();
    
    return {};
}

std::expected<void, TokenError> TokenGenerator::loadMergeRules(const std::string& mergesPath) {
    std::lock_guard lock(m_mutex);
    
    if (!fs::exists(mergesPath)) {
