    std::ifstream file(mergesPath);
    if (!file) {
        spdlog::error("Failed to open merge rules file: {}", mergesPath);
        return std::unexpected(TokenError::FileReadFailed);
    }
    
    // Clear existing rules
    m_mergeRules.clear();
    m_mergeRank.clear();
    
    // Load merge rules
    std::string line;
    int rank = 0;
    size_t lineNumber = 0;
    
    while (std::getline(file, line)) {
        lineNumber++;
        
        // Trim whitespace
        line.erase(0, line.find_first_not_of(" \t\r\n"));
        line.erase(line.find_last_not_of(" \t\r\n") + 1);
        
        if (line.empty() || line[0] == '#') {
            continue; // Skip comments and empty lines
        }
        
        // Parse format: "token1 token2"
        size_t spacePos = line.find(' ');
        if (spacePos == std::string::npos) {
            spdlog::warn("Invalid line {} in merge rules file: {}", lineNumber, line);
            continue;
        }
        
        std::string token1 = line.substr(0, spacePos);
        std::string token2 = line.substr(spacePos + 1);
        
        // Trim tokens
        token1.erase(0, token1.find_first_not_of(" \t"));
        token1.erase(token1.find_last_not_of(" \t") + 1);
        token2.erase(0, token2.find_first_not_of(" \t"));
        token2.erase(token2.find_last_not_of(" \t") + 1);
        
        m_mergeRules.push_back({token1, token2});
        m_mergeRank[{token1, token2}] = rank++;
    }
    
    spdlog::info("Loaded {} merge rules from {}", m_mergeRules.size(), mergesPath);
    
    // Clear cache
    clearCache();
    
    return {};
}

std::expected<void, TokenError> TokenGenerator::loadVocabularyFromModel(const std::string& modelPath) {
    if (!fs::exists(modelPath)) {
        return std::unexpected(TokenError::FileReadFailed);
    }
    
    // Try multiple possible locations for tokenizer files
    std::vector<std::string> possiblePaths = {
        modelPath + "/tokenizer.json",
        modelPath + "/tokenizer.model",
        modelPath + "/vocab.json",
        modelPath + "/vocab.txt",
        modelPath + "/merges.txt",
        fs::path(modelPath).parent_path().string() + "/tokenizer.json",
        fs::path(modelPath).parent_path().string() + "/tokenizer.model",
        fs::path(modelPath).parent_path().string() + "/vocab.json",
        fs::path(modelPath).parent_path().string() + "/vocab.txt",
        fs::path(modelPath).parent_path().string() + "/merges.txt"
    };
    
    bool loaded = false;
    
    for (const auto& path : possiblePaths) {
        if (fs::exists(path)) {
            if (path.find("tokenizer.json") != std::string::npos) {
                // Load from HuggingFace tokenizer.json
                auto result = loadVocabularyFromHuggingFace(path);
                if (result) {
                    loaded = true;
                    break;
                }
            } else if (path.find("tokenizer.model") != std::string::npos) {
                // Load from SentencePiece model
                auto result = loadVocabularyFromSentencePiece(path);
                if (result) {
                    loaded = true;
                    break;
                }
            } else if (path.find("vocab.json") != std::string::npos) {
                // Load from vocab.json
                auto result = loadVocabularyFromJSON(path);
                if (result) {
                    loaded = true;
                    break;
                }
            } else if (path.find("vocab.txt") != std::string::npos) {
                // Load from vocab.txt
                auto result = loadVocabulary(path);
                if (result) {
                    loaded = true;
                    break;
                }
            } else if (path.find("merges.txt") != std::string::npos) {
                // Load merge rules
                auto result = loadMergeRules(path);
                if (result) {
                    loaded = true;
                    break;
                }
            }
        }
    }
    
    if (!loaded) {
        spdlog::warn("No tokenizer files found in model directory: {}", modelPath);
        return std::unexpected(TokenError::VocabularyNotLoaded);
    }
    
    return {};
}

