std::expected<std::vector<int>, TokenError> TokenGenerator::getFromCache(
    const std::string& text,
    bool isEncode
) {
    if (!m_config.enableCache) {
        return std::unexpected(TokenError::TokenNotFound);
    }
    
    std::shared_lock lock(m_cacheMutex);
    
    const auto& cache = isEncode ? m_encodeCache : m_decodeCache;
    auto it = cache.find(text);
    if (it != cache.end()) {
        // Check if cache entry is still valid (not expired)
        auto now = std::chrono::steady_clock::now();
        auto age = now - it->second.timestamp;
        if (age < std::chrono::minutes(30)) { // 30 minute cache TTL
            return it->second.tokens;
        }
    }
    
    return std::unexpected(TokenError::TokenNotFound);
}

void TokenGenerator::addToCache(
    const std::string& text,
    const std::vector<int>& tokens,
    bool isEncode
) {
    if (!m_config.enableCache) {
        return;
    }
    
    std::lock_guard lock(m_cacheMutex);
    
    // Evict if cache is full
    evictCacheIfNeeded();
    
    CacheEntry entry;
    entry.tokens = tokens;
    entry.timestamp = std::chrono::steady_clock::now();
    
    if (isEncode) {
        m_encodeCache[text] = entry;
    } else {
        m_decodeCache[text] = entry;
    }
    
    m_cacheSize.fetch_add(1);
}

void TokenGenerator::evictCacheIfNeeded() {
    size_t currentSize = m_cacheSize.load();
    if (currentSize < m_config.maxCacheSize) {
        return;
    }
    
    // Evict oldest entries
    size_t targetSize = m_config.maxCacheSize * 0.8; // Keep 80%
    
    // Find oldest entries
    std::vector<std::pair<std::string, std::chrono::steady_clock::time_point>> entries;
    
    for (const auto& [key, entry] : m_encodeCache) {
        entries.push_back({key, entry.timestamp});
    }
    
    for (const auto& [key, entry] : m_decodeCache) {
        entries.push_back({key, entry.timestamp});
    }
    
    // Sort by timestamp (oldest first)
    std::sort(entries.begin(), entries.end(),
        [](const auto& a, const auto& b) {
            return a.second < b.second;
        });
    
    // Evict oldest entries
    size_t toEvict = currentSize - targetSize;
    for (size_t i = 0; i < toEvict && i < entries.size(); ++i) {
        m_encodeCache.erase(entries[i].first);
        m_decodeCache.erase(entries[i].first);
        m_cacheSize.fetch_sub(1);
    }
}

std::string TokenGenerator::detectTokenType(const std::string& token) const {
    if (token.substr(0, 3) == "▁") {
        return "subword_prefix";
    } else if (token.substr(token.length() - 4) == "</w>") {
        return "subword_suffix";
    } else if (token.substr(0, 2) == "##") {
        return "subword";
    } else if (token == "<pad>" || token == "<s>" || token == "</s>" || 
               token == "<unk>" || token == "<mask>") {
        return "special";
    } else if (std::all_of(token.begin(), token.end(), 
                          [](unsigned char c) { return std::ispunct(c); })) {
        return "punctuation";
    } else if (std::all_of(token.begin(), token.end(), 
                          [](unsigned char c) { return std::isdigit(c); })) {
        return "number";
    } else {
        return "word";
    }
}

