#include "agentic_ide.h"
#include "token_generator.h"
#include "net_impl_win32.h"
#include <CLI11.hpp>
#include <spdlog/spdlog.h>

int main(int argc, char* argv[]) {
    CLI::App app{"RawrXD v3.0 - Complete Agentic IDE with Real Tokenization"};
    
    // Configuration
    std::string configPath = "./config.json";
    app.add_option("-c,--config", configPath, "Configuration file path");
    
    std::string vocabPath;
    app.add_option("--vocab", vocabPath, "Vocabulary file path (tokenizer.json)");
    
    std::string mergesPath;
    app.add_option("--merges", mergesPath, "Merge rules file path (merges.txt)");
    
    std::string modelPath;
    app.add_option("-m,--model", modelPath, "Model directory path");
    
    // Tokenization options
    std::string tokenizationStrategy = "bpe";
    app.add_option("--token-strategy", tokenizationStrategy, 
                   "Tokenization strategy: bpe, wordpiece, sentencepiece")
        ->check(CLI::IsMember({"bpe", "wordpiece", "sentencepiece"}));
    
    bool enableCache = true;
    app.add_flag("--cache", enableCache, "Enable tokenization caching");
    
    // Mode
    std::string mode = "cli";
    app.add_option("--mode", mode, "Mode: cli, gui, server")
        ->check(CLI::IsMember({"cli", "gui", "server"}));
    
    CLI11_PARSE(app, argc, argv);
    
    // Setup logging
    spdlog::set_level(spdlog::level::debug);
    spdlog::set_pattern("[%Y-%m-%d %H:%M:%S.%e] [%^%l%$] %v");
    
    // Create tokenization config
    TokenizationConfig tokenConfig;
    tokenConfig.strategy = tokenizationStrategy == "bpe" ? TokenizationStrategy::BPE :
                          tokenizationStrategy == "wordpiece" ? TokenizationStrategy::WordPiece :
                          TokenizationStrategy::SentencePiece;
    tokenConfig.vocabPath = vocabPath;
    tokenConfig.mergesPath = mergesPath;
    tokenConfig.modelPath = modelPath;
    tokenConfig.enableCache = enableCache;
    tokenConfig.handleUnicode = true;
    tokenConfig.addPrefixSpace = true;
    tokenConfig.addSpecialTokens = true;
    
    // Create token generator
    TokenGenerator tokenizer(tokenConfig);
    
    // Load vocabulary
    if (!vocabPath.empty()) {
        auto result = tokenizer.loadVocabulary(vocabPath);
        if (!result) {
            spdlog::error("Failed to load vocabulary: {}", static_cast<int>(result.error()));
            return 1;
        }
        spdlog::info("Loaded vocabulary with {} tokens", tokenizer.getVocabSize());
    }
    
    // Load merge rules
    if (!mergesPath.empty()) {
        auto result = tokenizer.loadMergeRules(mergesPath);
        if (!result) {
            spdlog::error("Failed to load merge rules: {}", static_cast<int>(result.error()));
            return 1;
        }
        spdlog::info("Loaded {} merge rules", tokenizer.getMergeRulesSize());
    }
    
    // Load from model if path provided
    if (!modelPath.empty()) {
        auto result = tokenizer.loadVocabularyFromModel(modelPath);
        if (!result) {
            spdlog::warn("Failed to load vocabulary from model: {}", static_cast<int>(result.error()));
            spdlog::info("Created minimal vocabulary with {} tokens", tokenizer.getVocabSize());
        }
    }
    
    // Test tokenization
    spdlog::info("Testing tokenization...");
    std::string testText = "Hello world! This is a test of the token generator.";
    
    auto encodeResult = tokenizer.encode(testText);
    if (!encodeResult) {
        spdlog::error("Encoding failed: {}", static_cast<int>(encodeResult.error()));
        return 1;
    }
    
    auto tokens = encodeResult.value();
    spdlog::info("Encoded '{}' -> {} tokens", testText, tokens.size());
    
    // Show first 10 tokens
    std::string tokenStr;
    for (size_t i = 0; i < std::min(size_t(10), tokens.size()); ++i) {
        tokenStr += std::to_string(tokens[i]) + ",";
    }
    if (!tokenStr.empty()) tokenStr.pop_back();
    if (tokens.size() > 10) tokenStr += "...";
    spdlog::info("Tokens: [{}]", tokenStr);
    
    // Decode
    auto decodeResult = tokenizer.decode(tokens);
    if (!decodeResult) {
        spdlog::error("Decoding failed: {}", static_cast<int>(decodeResult.error()));
        return 1;
    }
    
    spdlog::info("Decoded -> '{}'", decodeResult.value());
    
    // Performance test
    spdlog::info("Running performance test...");
    std::string largeText = testText + " ";
    for (int i = 0; i < 100; ++i) {
        largeText += testText + " ";
    }
    
    auto start = std::chrono::steady_clock::now();
    auto result = tokenizer.encode(largeText);
    auto end = std::chrono::steady_clock::now();
    
    if (result) {
        auto duration = std::chrono::duration_cast<std::chrono::milliseconds>(end - start);
        spdlog::info("Tokenized {} characters -> {} tokens in {} ms ({} tokens/sec)",
                    largeText.length(), result->size(), duration.count(),
                    result->size() * 1000.0 / duration.count());
    }
    
    // Cache statistics
    auto status = tokenizer.getStatus();
    spdlog::info("Cache stats: {} hits, {} misses, {} entries",
                status["cache_hits"], status["cache_misses"], status["cache_size"]);
    
    // Create IDE
    IDEConfig ideConfig;
    ideConfig.modelsPath = modelPath;
    ideConfig.toolsPath = "./tools";
    ideConfig.maxWorkers = 4;
    ideConfig.enableChat = true;
    ideConfig.enableOrchestrator = true;
    ideConfig.enableZeroDay = true;
    ideConfig.enableSwarm = true;
    ideConfig.enableChainOfThought = true;
    ideConfig.logLevel = "debug";
    
    auto ide = std::make_shared<AgenticIDE>(ideConfig);
    
    // Initialize
    auto initResult = ide->initialize();
    if (!initResult) {
        spdlog::critical("IDE initialization failed: {}", static_cast<int>(initResult.error()));
        return 1;
    }
    
    // Start
    auto startResult = ide->start();
    if (!startResult) {
        spdlog::critical("IDE start failed: {}", static_cast<int>(startResult.error()));
        return 1;
    }
    
    // Run based on mode
    if (mode == "cli") {
        ide->processConsoleInput();
    } else if (mode == "gui") {
        // Create GUI
        RawrXD::Editor guiEditor;
        ide->setEditor(&guiEditor);
        guiEditor.run();
    } else if (mode == "server") {
        // Create HTTP server
        auto server = std::make_unique<GGUFAlpacaServer>(11434);
        
        // Add tokenization endpoint
        server->addEndpoint("/api/tokenize", [&tokenizer](const json& req) {
            std::string text = req.value("text", "");
            auto result = tokenizer.encode(text);
            if (!result) {
                return json{{"error", "Tokenization failed"}};
            }
            return json{{"tokens", result.value()}};
        });
        
        // Add detokenization endpoint
        server->addEndpoint("/api/detokenize", [&tokenizer](const json& req) {
            std::vector<int> tokens = req.value("tokens", std::vector<int>());
            auto result = tokenizer.decode(tokens);
            if (!result) {
                return json{{"error", "Detokenization failed"}};
            }
            return json{{"text", result.value()}};
        });
        
        server->run();
    }
    
    // Cleanup
    ide->stop();
    
    spdlog::info("RawrXD v3.0 shutdown complete");
    return 0;
}
