// Real SPIR-V shaders with wavefront optimization
static const char* MATMUL_SHADER = R"(
#version 450
#extension GL_KHR_shader_subgroup_basic : require
#extension GL_KHR_shader_subgroup_ballot : require
#extension GL_KHR_shader_subgroup_arithmetic : require

layout(local_size_x = 256) in;

layout(binding = 0) readonly buffer InputA {
    float a[];
};

layout(binding = 1) readonly buffer InputB {
    float b[];
};

layout(binding = 2) writeonly buffer Output {
    float result[];
};

layout(push_constant) uniform PushConstants {
    uint dim;
    uint wavefrontSize;
} push;

void main() {
    uint idx = gl_GlobalInvocationID.x;
    uint wavefront = idx / push.wavefrontSize;
    uint lane = idx % push.wavefrontSize;
    
    // Wavefront-optimized matrix multiplication
    float sum = 0.0;
    uint row = idx / push.dim;
    uint col = idx % push.dim;
    
    // Use subgroup operations for better performance
    for (uint k = 0; k < push.dim; k += push.wavefrontSize) {
        uint aIndex = row * push.dim + k + lane;
        uint bIndex = (k + lane) * push.dim + col;
        
        if (aIndex < push.dim * push.dim && bIndex < push.dim * push.dim) {
            float aVal = subgroupBroadcast(a[aIndex], lane);
            float bVal = subgroupBroadcast(b[bIndex], lane);
            sum += aVal * bVal;
        }
    }
    
    // Subgroup reduction for final sum
    sum = subgroupAdd(sum);
    
    if (lane == 0) {
        result[idx] = sum;
    }
}
)";

static const char* SOFTMAX_SHADER = R"(
#version 450
#extension GL_KHR_shader_subgroup_basic : require
#extension GL_KHR_shader_subgroup_ballot : require
#extension GL_KHR_shader_subgroup_arithmetic : require

layout(local_size_x = 256) in;

layout(binding = 0) buffer Logits {
    float logits[];
};

layout(binding = 1) writeonly buffer Output {
    float probs[];
};

layout(push_constant) uniform PushConstants {
    float temperature;
    uint vocabSize;
    uint wavefrontSize;
} push;

void main() {
    uint idx = gl_GlobalInvocationID.x;
    uint wavefront = idx / push.wavefrontSize;
    uint lane = idx % push.wavefrontSize;
    
    // Wavefront-optimized softmax with numerical stability
    float maxLogit = -1e20;
    
    // Find max in wavefront
    for (uint i = 0; i < push.vocabSize; i += push.wavefrontSize) {
        uint index = i + lane;
        if (index < push.vocabSize) {
            float logit = subgroupBroadcast(logits[index], lane);
            maxLogit = max(maxLogit, logit);
        }
    }
    
    // Subgroup reduction for max
    maxLogit = subgroupMax(maxLogit);
    
    // Calculate exp and sum
    float sum = 0.0;
    for (uint i = 0; i < push.vocabSize; i += push.wavefrontSize) {
        uint index = i + lane;
        if (index < push.vocabSize) {
            float logit = subgroupBroadcast(logits[index], lane);
            float expVal = exp((logit - maxLogit) / push.temperature);
            sum += expVal;
            probs[index] = expVal;
        }
    }
    
    // Subgroup reduction for sum
    sum = subgroupAdd(sum);
    
    // Normalize
    for (uint i = lane; i < push.vocabSize; i += push.wavefrontSize) {
        probs[i] /= sum;
    }
}
)";

