std::expected<VulkanBuffer, VulkanError> VulkanCompute::createBuffer(
    size_t size,
    VkBufferUsageFlags usage,
    VkMemoryPropertyFlags properties,
    bool zeroCopy
) {
    VulkanBuffer buffer;
    buffer.size = size;
    
    VkBufferCreateInfo bufferInfo{};
    bufferInfo.sType = VK_STRUCTURE_TYPE_BUFFER_CREATE_INFO;
    bufferInfo.size = size;
    bufferInfo.usage = usage;
    bufferInfo.sharingMode = VK_SHARING_MODE_EXCLUSIVE;
    
    VmaAllocationCreateInfo allocInfo{};
    allocInfo.usage = VMA_MEMORY_USAGE_GPU_ONLY;
    if (zeroCopy) {
        allocInfo.flags = VMA_ALLOCATION_CREATE_MAPPED_BIT;
        allocInfo.requiredFlags = VK_MEMORY_PROPERTY_HOST_VISIBLE_BIT | 
                                 VK_MEMORY_PROPERTY_HOST_COHERENT_BIT;
    }
    
    VmaAllocation allocation;
    if (vmaCreateBuffer(m_allocator, &bufferInfo, &allocInfo, 
                       &buffer.buffer, &allocation, nullptr) != VK_SUCCESS) {
        return std::unexpected(VulkanError::MemoryAllocationFailed);
    }
    
    if (zeroCopy) {
        vmaMapMemory(m_allocator, allocation, &buffer.mappedMemory);
    }
    
    buffer.isValid = true;
    buffer.lastUsed = std::chrono::steady_clock::now();
    
    trackMemoryUsage(size);
    updatePeakMemoryUsage(size);
    
    // Add to cache
    std::lock_guard lock(m_bufferMutex);
    m_bufferCache[buffer.mappedMemory] = buffer;
    
    return buffer;
}

std::expected<void, VulkanError> VulkanCompute::executeMatrixMultiplication(
    const VulkanBuffer& a,
    const VulkanBuffer& b,
    VulkanBuffer& result,
    size_t dim,
    bool useWavefront
) {
    std::lock_guard lock(m_pipelineMutex);
    
    auto it = m_pipelines.find("matmul");
    if (it == m_pipelines.end() || !it->second.isValid) {
        return std::unexpected(VulkanError::PipelineCreationFailed);
    }
    
    auto& pipeline = it->second;
    
    // Allocate descriptor set
    auto descriptorResult = allocateDescriptorSet(pipeline.layout);
    if (!descriptorResult) {
        return std::unexpected(descriptorResult.error());
    }
    
    VkDescriptorSet descriptorSet = descriptorResult.value();
    
    // Update descriptor set
    VkWriteDescriptorSet descriptorWrites[3];
    
    // Input A
    descriptorWrites[0].sType = VK_STRUCTURE_TYPE_WRITE_DESCRIPTOR_SET;
    descriptorWrites[0].dstSet = descriptorSet;
    descriptorWrites[0].dstBinding = 0;
    descriptorWrites[0].dstArrayElement = 0;
    descriptorWrites[0].descriptorType = VK_DESCRIPTOR_TYPE_STORAGE_BUFFER;
    descriptorWrites[0].descriptorCount = 1;
    descriptorWrites[0].pBufferInfo = &(VkDescriptorBufferInfo{a.buffer, 0, VK_WHOLE_SIZE});
    
    // Input B
    descriptorWrites[1].sType = VK_STRUCTURE_TYPE_WRITE_DESCRIPTOR_SET;
    descriptorWrites[1].dstSet = descriptorSet;
    descriptorWrites[1].dstBinding = 1;
    descriptorWrites[1].dstArrayElement = 0;
    descriptorWrites[1].descriptorType = VK_DESCRIPTOR_TYPE_STORAGE_BUFFER;
    descriptorWrites[1].descriptorCount = 1;
    descriptorWrites[1].pBufferInfo = &(VkDescriptorBufferInfo{b.buffer, 0, VK_WHOLE_SIZE});
    
    // Output
    descriptorWrites[2].sType = VK_STRUCTURE_TYPE_WRITE_DESCRIPTOR_SET;
    descriptorWrites[2].dstSet = descriptorSet;
    descriptorWrites[2].dstBinding = 2;
    descriptorWrites[2].dstArrayElement = 0;
    descriptorWrites[2].descriptorType = VK_DESCRIPTOR_TYPE_STORAGE_BUFFER;
    descriptorWrites[2].descriptorCount = 1;
    descriptorWrites[2].pBufferInfo = &(VkDescriptorBufferInfo{result.buffer, 0, VK_WHOLE_SIZE});
    
    vkUpdateDescriptorSets(m_device, 3, descriptorWrites, 0, nullptr);
    
    // Begin command buffer
    auto cmdBufferResult = beginCommandBuffer();
    if (!cmdBufferResult) {
        return std::unexpected(cmdBufferResult.error());
    }
    
    VkCommandBuffer cmdBuffer = cmdBufferResult.value();
    
    // Bind pipeline
    vkCmdBindPipeline(cmdBuffer, VK_PIPELINE_BIND_POINT_COMPUTE, pipeline.pipeline);
    
    // Bind descriptor set
    vkCmdBindDescriptorSets(cmdBuffer, VK_PIPELINE_BIND_POINT_COMPUTE, 
                           pipeline.layout, 0, 1, &descriptorSet, 0, nullptr);
    
    // Push constants
    struct PushConstants {
        uint32_t dim;
        uint32_t wavefrontSize;
    } pushConstants{
        static_cast<uint32_t>(dim),
        32 // AMD wavefront size, 32 for NVIDIA
    };
    
    vkCmdPushConstants(cmdBuffer, pipeline.layout, VK_SHADER_STAGE_COMPUTE_BIT, 
                      0, sizeof(pushConstants), &pushConstants);
    
    // Dispatch with optimal workgroup size
    uint32_t groupSize = 256;
    uint32_t groupCount = (dim * dim + groupSize - 1) / groupSize;
    
    vkCmdDispatch(cmdBuffer, groupCount, 1, 1);
    
    // End command buffer
    auto endResult = endCommandBuffer(cmdBuffer);
    if (!endResult) {
        return std::unexpected(endResult.error());
    }
    
    // Submit command buffer
    VkSubmitInfo submitInfo{};
    submitInfo.sType = VK_STRUCTURE_TYPE_SUBMIT_INFO;
    submitInfo.commandBufferCount = 1;
    submitInfo.pCommandBuffers = &cmdBuffer;
    
    auto startTime = std::chrono::steady_clock::now();
    
    if (vkQueueSubmit(m_computeQueue, 1, &submitInfo, VK_NULL_HANDLE) != VK_SUCCESS) {
        return std::unexpected(VulkanError::KernelExecutionFailed);
    }
    
    // Wait for completion
    if (vkQueueWaitIdle(m_computeQueue) != VK_SUCCESS) {
        return std::unexpected(VulkanError::SynchronizationFailed);
    }
    
    auto endTime = std::chrono::steady_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::nanoseconds>(endTime - startTime);
    
    // Record performance metrics
    size_t memoryTransferred = (a.size + b.size + result.size);
    recordPerformanceMetrics("matmul", duration, memoryTransferred);
    
    // Update buffer usage
    result.lastUsed = std::chrono::steady_clock::now();
    
    return {};
}

std::expected<std::vector<uint32_t>, VulkanError> VulkanCompute::compileGLSLToSPIRV(
    const std::string& glslCode,
    const std::string& entryPoint,
    bool optimize
) {
    shaderc::Compiler compiler;
    shaderc::CompileOptions options;
    
    if (optimize) {
        options.SetOptimizationLevel(shaderc_optimization_level_performance);
        options.SetForcedVersionProfile(450, shaderc_profile_core);
        options.SetGenerateDebugInfo(false);
    }
    
    // Enable subgroup operations
    options.AddMacroDefinition("GL_KHR_shader_subgroup_basic", "1");
    options.AddMacroDefinition("GL_KHR_shader_subgroup_ballot", "1");
    options.AddMacroDefinition("GL_KHR_shader_subgroup_arithmetic", "1");
    
    auto result = compiler.CompileGlslToSpv(
        glslCode,
        shaderc_glsl_compute_shader,
        entryPoint.c_str(),
        options
    );
    
    if (result.GetCompilationStatus() != shaderc_compilation_status_success) {
        spdlog::error("Shader compilation failed: {}", result.GetErrorMessage());
        return std::unexpected(VulkanError::ShaderCompilationFailed);
    }
    
    return std::vector<uint32_t>(result.begin(), result.end());
}

void VulkanCompute::recordPerformanceMetrics(
    const std::string& operation,
    std::chrono::nanoseconds duration,
    size_t memoryTransferred
) {
    m_totalOperations.fetch_add(1);
    m_totalExecutionTime.fetch_add(duration);
    m_totalMemoryTransferred.fetch_add(memoryTransferred);
    
    // Calculate FLOPs for matmul
    if (operation == "matmul") {
        size_t dim = static_cast<size_t>(std::sqrt(memoryTransferred / 3 / sizeof(float)));
        uint64_t flops = 2 * dim * dim * dim; // 2 * N^3 for matrix multiplication
        double gflops = static_cast<double>(flops) / duration.count() / 1e9;
        spdlog::debug("Matmul performance: {:.2f} GFLOPs", gflops);
    }
    
    // Calculate memory bandwidth
    double bandwidth = static_cast<double>(memoryTransferred) / duration.count() / 1e9;
    spdlog::debug("Memory bandwidth: {:.2f} GB/s", bandwidth);
}

double VulkanCompute::getGFlops() const {
    auto totalTime = m_totalExecutionTime.load();
    if (totalTime.count() == 0) return 0.0;
    
    // Estimate FLOPs from operations (simplified)
    uint64_t totalFlops = m_totalOperations.load() * 1000000; // Assume 1MFLOP per operation
    return static_cast<double>(totalFlops) / totalTime.count() / 1e9;
}

double VulkanCompute::getMemoryBandwidth() const {
    auto totalTime = m_totalExecutionTime.load();
    if (totalTime.count() == 0) return 0.0;
    
    return static_cast<double>(m_totalMemoryTransferred.load()) / totalTime.count() / 1e9;
}

json VulkanCompute::getPerformanceMetrics() const {
    return {
        {"total_operations", m_totalOperations.load()},
        {"total_execution_time_ns", m_totalExecutionTime.load().count()},
        {"total_memory_transferred_mb", m_totalMemoryTransferred.load() / (1024 * 1024)},
        {"peak_memory_usage_mb", m_peakMemoryUsage.load() / (1024 * 1024)},
        {"gflops", getGFlops()},
        {"memory_bandwidth_gbs", getMemoryBandwidth()},
        {"device_name", m_deviceProperties.deviceName},
        {"max_work_group_size", m_deviceProperties.limits.maxComputeWorkGroupSize[0]}
    };
}

