std::expected<ConsensusResult, SwarmError> SwarmOrchestrator::executeTask(
    const std::string& task
) {
    if (!m_initialized.load()) {
        return std::unexpected(SwarmError::AgentCreationFailed);
    }
    
    logSwarmOperation("executeTask", std::format("Task: {}", task));
    
    // Create task context
    std::unordered_map<std::string, std::string> context;
    context["original_task"] = task;
    context["timestamp"] = std::to_string(
        std::chrono::system_clock::to_time_t(std::chrono::system_clock::now())
    );
    context["user_id"] = "system"; // Would be extracted from task
    
    // Real task decomposition using LLM
    auto decompositionResult = decomposeTask(task, context);
    if (!decompositionResult) {
        spdlog::error("Task decomposition failed: {}", 
                     static_cast<int>(decompositionResult.error()));
        // Fallback to simple decomposition
        decompositionResult = std::vector<std::string>{
            "Analyze requirements and constraints",
            "Design solution architecture",
            "Implement core functionality",
            "Test and validate results",
            "Optimize performance if needed"
        };
    }
    
    auto subtasks = decompositionResult.value();
    spdlog::debug("Decomposed task into {} subtasks", subtasks.size());
    
    // Create swarm task
    auto swarmTask = std::make_unique<SwarmTask>();
    swarmTask->id = generateTaskId();
    swarmTask->description = task;
    swarmTask->subtasks = subtasks;
    swarmTask->context = context;
    swarmTask->createdAt = std::chrono::steady_clock::now();
    swarmTask->timeout = m_defaultTimeout;
    swarmTask->requiredConfidence = m_requiredConfidence;
    
    // Submit task
    auto submitResult = submitTask(std::move(swarmTask));
    if (!submitResult) {
        return std::unexpected(submitResult.error());
    }
    
    // Wait for completion with timeout
    auto startTime = std::chrono::steady_clock::now();
    while (m_running.load()) {
        {
            std::lock_guard lock(m_taskMutex);
            auto it = m_completedTasks.find(swarmTask->id);
            if (it != m_completedTasks.end() && it->second->isCompleted.load()) {
                // Collect results from all subtasks
                std::vector<SwarmResult> results;
                
                for (const auto& subtask : it->second->subtasks) {
                    // Find result for this subtask
                    auto resultIt = std::find_if(
                        m_subtaskResults.begin(),
                        m_subtaskResults.end(),
                        [&subtask](const SwarmResult& r) {
                            return r.result.find(subtask) != std::string::npos;
                        }
                    );
                    
                    if (resultIt != m_subtaskResults.end()) {
                        results.push_back(*resultIt);
                    }
                }
                
                // Reach consensus
                auto consensusResult = reachConsensus(results, *it->second);
                if (consensusResult) {
                    spdlog::info("Task {} completed with consensus confidence: {:.2f}", 
                               it->second->id, consensusResult->confidence);
                    return consensusResult.value();
                } else {
                    spdlog::error("Consensus failed for task {}: {}", 
                                it->second->id, static_cast<int>(consensusResult.error()));
                    return std::unexpected(consensusResult.error());
                }
            }
        }
        
        // Check timeout
        auto elapsed = std::chrono::steady_clock::now() - startTime;
        if (elapsed > swarmTask->timeout) {
            spdlog::error("Task {} timed out after {} ms", 
                        swarmTask->id, 
                        std::chrono::duration_cast<std::chrono::milliseconds>(elapsed).count());
            
            // Cancel task
            cancelTask(swarmTask->id);
            return std::unexpected(SwarmError::Timeout);
        }
        
        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }
    
    return std::unexpected(SwarmError::Cancelled);
}

std::expected<void, SwarmError> SwarmOrchestrator::submitTask(
    std::unique_ptr<SwarmTask> task
) {
    std::lock_guard lock(m_taskMutex);
    
    if (m_activeTasks.size() >= m_maxAgents * 2) {
        return std::unexpected(SwarmError::ResourceExhausted);
    }
    
    task->id = generateTaskId();
    m_taskQueue.push_back(std::move(task));
    m_taskCondition.notify_one();
    
    // Add to stealable tasks
    if (m_workStealingEnabled) {
        std::lock_guard stealLock(m_stealMutex);
        m_stealableTasks.push_back(m_taskQueue.back()->id);
    }
    
    logSwarmOperation("submitTask", std::format("Task ID: {}", m_taskQueue.back()->id));
    
    return {};
}

std::expected<ConsensusResult, SwarmError> SwarmOrchestrator::reachConsensus(
    const std::vector<SwarmResult>& results,
    const SwarmTask& task
) {
    if (results.empty()) {
        return std::unexpected(SwarmError::ConsensusFailed);
    }
    
    if (results.size() == 1) {
        // Single result, no consensus needed
        ConsensusResult consensus;
        consensus.consensus = results[0].result;
        consensus.confidence = results[0].confidence;
        consensus.supportingAgents.push_back(results[0].agentId);
        consensus.reasoning.push_back("Single agent result");
        consensus.individualResults = results;
        return consensus;
    }
    
    // Check for conflicts
    bool hasConflicts = false;
    for (size_t i = 1; i < results.size(); ++i) {
        if (results[i].result != results[0].result) {
            hasConflicts = true;
            break;
        }
    }
    
    if (hasConflicts) {
        // Use iterative refinement for conflicting results
        return iterativeRefinementConsensus(results, task);
    } else {
        // Use confidence-weighted consensus for agreement
        return confidenceWeightedConsensus(results, task);
    }
}

std::expected<ConsensusResult, SwarmError> SwarmOrchestrator::iterativeRefinementConsensus(
    const std::vector<SwarmResult>& results,
    const SwarmTask& task
) {
    spdlog::debug("Performing iterative refinement consensus for {} results", results.size());
    
    ConsensusResult consensus;
    consensus.confidence = 0.0f;
    consensus.individualResults = results;
    
    // Group results by similarity
    std::unordered_map<std::string, std::vector<const SwarmResult*>> resultGroups;
    for (const auto& result : results) {
        resultGroups[result.result].push_back(&result);
    }
    
    // Find majority group
    std::string majorityResult;
    size_t majorityCount = 0;
    std::vector<const SwarmResult*> majorityGroup;
    
    for (const auto& [result, group] : resultGroups) {
        if (group.size() > majorityCount) {
            majorityCount = group.size();
            majorityResult = result;
            majorityGroup = group;
        }
    }
    
    // Calculate weighted confidence for majority
    float totalConfidence = 0.0f;
    for (const auto* result : majorityGroup) {
        totalConfidence += result->confidence;
        consensus.supportingAgents.push_back(result->agentId);
    }
    
    consensus.confidence = totalConfidence / majorityGroup.size();
    consensus.consensus = majorityResult;
    
    // Add reasoning
    consensus.reasoning.push_back(std::format(
        "Majority consensus with {} of {} agents (confidence: {:.2f})",
        majorityGroup.size(), results.size(), consensus.confidence
    ));
    
    // Add dissenting agents
    for (const auto& [result, group] : resultGroups) {
        if (result != majorityResult) {
            for (const auto* resultPtr : group) {
                consensus.dissentingAgents.push_back(resultPtr->agentId);
            }
        }
    }
    
    // If confidence is too low, request refinement
    if (consensus.confidence < task.requiredConfidence) {
        spdlog::warn("Consensus confidence {:.2f} below required {:.2f}, requesting refinement",
                    consensus.confidence, task.requiredConfidence);
        
        // Create refinement prompt
        std::string refinementPrompt = std::format(
            "The following results have low confidence ({:.2f}). "
            "Please refine and improve the solution.\n\n"
            "Original task: {}\n"
            "Current consensus: {}\n"
            "Supporting agents: {}\n"
            "Dissenting agents: {}\n\n"
            "Refined solution:\n",
            consensus.confidence,
            task.description,
            consensus.consensus,
            [&]() {
                std::string agents;
                for (const auto& id : consensus.supportingAgents) {
                    agents += id + ", ";
                }
                return agents.empty() ? "none" : agents.substr(0, agents.length() - 2);
            }(),
            [&]() {
                std::string agents;
                for (const auto& id : consensus.dissentingAgents) {
                    agents += id + ", ";
                }
                return agents.empty() ? "none" : agents.substr(0, agents.length() - 2);
            }()
        );
        
        // Use best agent to refine
        auto bestAgent = selectAgentsForTask(task, 1);
        if (bestAgent && !bestAgent->empty()) {
            auto refinementResult = executeSubtask(
                bestAgent->front(), 
                refinementPrompt, 
                task.context,
                std::chrono::milliseconds(10000)
            );
            
            if (refinementResult) {
                consensus.consensus = refinementResult->result;
                consensus.confidence = refinementResult->confidence;
                consensus.reasoning.push_back("Refined by best agent");
            }
        }
    }
    
    return consensus;
}

void SwarmOrchestrator::workStealingLoop() {
    spdlog::info("Work stealing thread started");
    
    while (m_running.load()) {
        std::this_thread::sleep_for(std::chrono::milliseconds(m_workStealingIntervalMs));
        
        if (!m_workStealingEnabled.load()) {
            continue;
        }
        
        // Find busy agents and idle agents
        std::vector<SwarmAgent*> busyAgents;
        std::vector<SwarmAgent*> idleAgents;
        
        {
            std::lock_guard lock(m_agentMutex);
            
            for (auto& agent : m_agents) {
                if (agent->isBusy.load() && agent->taskQueue.size() > 1) {
                    busyAgents.push_back(agent.get());
                } else if (!agent->isBusy.load()) {
                    idleAgents.push_back(agent.get());
                }
            }
        }
        
        // Attempt work stealing
        if (!busyAgents.empty() && !idleAgents.empty()) {
            // Sort busy agents by queue size (descending)
            std::sort(busyAgents.begin(), busyAgents.end(),
                [](const SwarmAgent* a, const SwarmAgent* b) {
                    return a->taskQueue.size() > b->taskQueue.size();
                });
            
            // Sort idle agents by last activity (ascending)
            std::sort(idleAgents.begin(), idleAgents.end(),
                [](const SwarmAgent* a, const SwarmAgent* b) {
                    return a->lastActive < b->lastActive;
                });
            
            // Attempt steals
            for (auto* thief : idleAgents) {
                if (thief->isStealing.load()) {
                    continue; // Already stealing
                }
                
                for (auto* victim : busyAgents) {
                    if (victim == thief || victim->taskQueue.size() <= 1) {
                        continue;
                    }
                    
                    // Attempt steal
                    auto stealResult = stealWork(thief, victim);
                    if (stealResult) {
                        m_workStealCount.fetch_add(1);
                        spdlog::debug("Work stolen: {} -> {}", victim->id, thief->id);
                        break;
                    }
                }
            }
        }
    }
    
    spdlog::info("Work stealing thread stopped");
}

std::expected<void, SwarmError> SwarmOrchestrator::stealWork(
    SwarmAgent* thief,
    SwarmAgent* victim
) {
    if (!thief || !victim || thief == victim) {
        return std::unexpected(SwarmError::InvalidAgent);
    }
    
    // Mark agents as stealing
    thief->isStealing = true;
    victim->isStealing = true;
    
    // Try to steal half the tasks
    size_t tasksToSteal = victim->taskQueue.size() / 2;
    if (tasksToSteal == 0) {
        thief->isStealing = false;
        victim->isStealing = false;
        return std::unexpected(SwarmError::WorkStealingFailed);
    }
    
    // Transfer tasks
    for (size_t i = 0; i < tasksToSteal; ++i) {
        if (victim->taskQueue.empty()) {
            break;
        }
        
        std::string taskId = victim->taskQueue.back();
        victim->taskQueue.pop_back();
        thief->taskQueue.push_front(taskId);
    }
    
    thief->isStealing = false;
    victim->isStealing = false;
    thief->lastStealAttempt = std::chrono::steady_clock::now();
    
    logSwarmOperation("stealWork", std::format("{} -> {} ({} tasks)", 
                                              victim->id, thief->id, tasksToSteal));
    
    return {};
}

std::expected<float, SwarmError> SwarmOrchestrator::calculateAgentScore(
    const SwarmAgent* agent,
    const SwarmTask& task
) {
    float score = 0.0f;
    
    // Base score from agent confidence
    score += agent->confidence.load() * 0.3f;
    
    // Score from specialization match
    std::string taskLower = task.description;
    std::transform(taskLower.begin(), taskLower.end(), taskLower.begin(), ::tolower);
    
    for (const auto& cap : agent->capabilities) {
        std::string capStr = specializationToString(cap);
        std::transform(capStr.begin(), capStr.end(), capStr.begin(), ::tolower);
        
        if (taskLower.find(capStr) != std::string::npos) {
            score += agent->specializationScores.at(capStr) * 0.4f;
        }
    }
    
    // Score from success rate
    score += agent->successRate.load() * 0.2f;
    
    // Penalty for long execution time
    float timePenalty = 1.0f / (1.0f + agent->averageExecutionTime.count() / 1000.0f);
    score += timePenalty * 0.1f;
    
    // Bonus for recent activity (warm cache)
    auto hoursSinceActive = std::chrono::duration_cast<std::chrono::hours>(
        std::chrono::steady_clock::now() - agent->lastActive).count();
    if (hoursSinceActive < 1) {
        score += 0.05f; // Small bonus for warm cache
    }
    
    return score;
}

} // namespace RawrXD
