#include "chain_of_thought.h"
#include <sstream>
#include <algorithm>
#include <random>
#include <chrono>
#include <iomanip>

namespace RawrXD {

ChainOfThought::ChainOfThought() {
    // Get inference engine from global context
    // In production, this would be dependency injected
    m_inferenceEngine = CPUInferenceEngine::getInstance();
    m_tokenizer = TokenGenerator::getInstance();
}

std::expected<ReasoningChain, ChainError> ChainOfThought::generateChain(
    const std::string& goal,
    const std::unordered_map<std::string, std::string>& context
) {
    ReasoningChain chain;
    chain.id = generateStepId();
    chain.goal = goal;
    chain.context = context;
    chain.startTime = std::chrono::steady_clock::now();
    
    spdlog::info("Generating reasoning chain for: {}", goal);
    
    // Initial context analysis
    ThoughtStep initialStep;
    initialStep.id = generateStepId();
    initialStep.content = "Analyze problem context and identify key requirements";
    initialStep.reasoning = "Starting reasoning process with context analysis";
    initialStep.confidence = 0.9f;
    initialStep.timestamp = std::chrono::steady_clock::now();
    initialStep.isValidated = true;
    
    chain.steps.push_back(initialStep);
    
    // Run reasoning loop with revision
    auto loopResult = runReasoningLoop(chain, 10); // Max 10 iterations
    if (!loopResult) {
        return std::unexpected(loopResult.error());
    }
    
    chain = loopResult.value();
    
    // Identify contradictions
    auto contradictionResult = identifyContradictions(chain);
    if (contradictionResult) {
        chain.contradictions = contradictionResult.value();
    }
    
    // Identify knowledge gaps
    auto gapResult = identifyKnowledgeGaps(chain);
    if (gapResult) {
        chain.unresolvedQuestions = gapResult.value();
    }
    
    // Calculate overall confidence
    float totalConfidence = 0.0f;
    for (const auto& step : chain.steps) {
        totalConfidence += step.confidence;
    }
    chain.overallConfidence = totalConfidence / chain.steps.size();
    
    chain.endTime = std::chrono::steady_clock::now();
    chain.isComplete = true;
    
    spdlog::info("Reasoning chain completed with {} steps, confidence: {:.2f}", 
                chain.steps.size(), chain.overallConfidence);
    
    return chain;
}

std::expected<ReasoningChain, ChainError> ChainOfThought::runReasoningLoop(
    ReasoningChain& chain,
    size_t maxIterations
) {
    size_t iteration = 0;
    
    while (iteration < maxIterations && !chain.isComplete) {
        // Generate next step
        auto stepResult = generateNextStep(chain, chain.steps);
        if (!stepResult) {
            // If generation fails, try to formulate hypothesis
            auto hypothesisResult = formulateHypothesis(chain);
            if (hypothesisResult) {
                ThoughtStep hypothesisStep;
                hypothesisStep.id = generateStepId();
                hypothesisStep.content = hypothesisResult.value();
                hypothesisStep.reasoning = "Formulated hypothesis based on available evidence";
                hypothesisStep.confidence = 0.6f; // Hypotheses have lower confidence
                hypothesisStep.isAssumption = true;
                hypothesisStep.timestamp = std::chrono::steady_clock::now();
                
                chain.steps.push_back(hypothesisStep);
                
                // Test hypothesis
                auto testResult = testHypothesis(hypothesisStep.content, chain);
                if (testResult && testResult.value()) {
                    // Hypothesis validated
                    chain.steps.back().isValidated = true;
                    chain.steps.back().confidence = 0.8f;
                } else {
                    // Hypothesis rejected, backtrack
                    auto backtrackResult = backtrack(chain, chain.steps.size() - 1);
                    if (!backtrackResult) {
                        return std::unexpected(backtrackResult.error());
                    }
                    chain = backtrackResult.value();
                }
            } else {
                return std::unexpected(stepResult.error());
            }
        } else {
            ThoughtStep step = stepResult.value();
            
            // Validate step
            auto validationResult = validateStep(step, chain);
            if (validationResult && validationResult.value()) {
                step.isValidated = true;
                
                // Calculate confidence
                auto confidenceResult = calculateStepConfidence(step, chain);
                if (confidenceResult) {
                    step.confidence = confidenceResult.value();
                }
                
                chain.steps.push_back(step);
                
                // Check if goal is reached
                if (step.content.find(chain.goal) != std::string::npos || 
                    step.conclusions.contains(chain.goal)) {
                    chain.isComplete = true;
                    break;
                }
                
                // Check for knowledge gaps
                auto gaps = identifyKnowledgeGaps(chain);
                if (gaps && !gaps->empty()) {
                    // Formulate hypothesis to fill gaps
                    auto hypothesisResult = formulateHypothesis(chain);
                    if (hypothesisResult) {
                        ThoughtStep hypothesisStep;
                        hypothesisStep.id = generateStepId();
                        hypothesisStep.content = hypothesisResult.value();
                        hypothesisStep.reasoning = "Hypothesis to fill knowledge gap";
                        hypothesisStep.confidence = 0.5f;
                        hypothesisStep.isAssumption = true;
                        hypothesisStep.timestamp = std::chrono::steady_clock::now();
                        
                        chain.steps.push_back(hypothesisStep);
                    }
                }
            } else {
                // Validation failed, try to revise
                auto reviseResult = reviseStep(step, chain, "Validation failed");
                if (reviseResult) {
                    chain.steps.push_back(step);
                } else {
                    // Backtrack if revision fails
                    auto backtrackResult = backtrack(chain, chain.steps.size() - 1);
                    if (!backtrackResult) {
                        return std::unexpected(backtrackResult.error());
                    }
                    chain = backtrackResult.value();
                }
            }
        }
        
        iteration++;
        
        // Check for contradictions
        auto contradictionResult = identifyContradictions(chain);
        if (contradictionResult && !contradictionResult->empty()) {
            // Resolve contradictions
            for (const auto& contradiction : contradictionResult.value()) {
                spdlog::warn("Contradiction detected: {}", contradiction);
                
                // Find steps involved in contradiction
                auto resolveResult = resolveConflicts(chain, contradiction);
                if (!resolveResult) {
                    return std::unexpected(resolveResult.error());
                }
                chain = resolveResult.value();
            }
        }
    }
    
    if (iteration >= maxIterations && !chain.isComplete) {
        return std::unexpected(ChainError::MaxDepthExceeded);
    }
    
    return chain;
}

std::expected<ThoughtStep, ChainError> ChainOfThought::generateNextStep(
    const ReasoningChain& chain,
    const std::vector<ThoughtStep>& previousSteps
) {
    ThoughtStep step;
    step.id = generateStepId();
    step.timestamp = std::chrono::steady_clock::now();
    
    // Create prompt based on previous steps and context
    std::string prompt = std::format(
        "Continue the following reasoning process. "
        "Each step should build on previous steps and move toward the goal.\n\n"
        "Goal: {}\n"
        "Context:\n{}\n\n"
        "Previous reasoning:\n",
        chain.goal,
        [&]() {
            std::string ctx;
            for (const auto& [key, value] : chain.context) {
                ctx += key + ": " + value + "\n";
            }
            return ctx;
        }()
    );
    
    for (const auto& prevStep : previousSteps) {
        prompt += std::format("{}. {} (confidence: {:.2f})\n", 
                              prevStep.id, prevStep.content, prevStep.confidence);
    }
    
    prompt += "\nNext reasoning step:\n";
    
    // Use inference engine for real step generation
    auto result = m_inferenceEngine->generate(prompt, 0.7f, 0.9f, 300);
    if (!result) {
        return std::unexpected(ChainError::StepGenerationFailed);
    }
    
    // Parse generated step
    std::string generated = result->text;
    step.content = generated.substr(0, generated.find("\n"));
    step.reasoning = "Generated based on previous steps and context";
    step.confidence = 0.8f; // Default confidence
    
    // Extract premises and conclusions
    size_t premisePos = generated.find("Premise:");
    if (premisePos != std::string::npos) {
        size_t endPos = generated.find("\n", premisePos);
        step.premises.push_back(generated.substr(premisePos + 8, endPos - premisePos - 8));
    }
    
    size_t conclusionPos = generated.find("Conclusion:");
    if (conclusionPos != std::string::npos) {
        size_t endPos = generated.find("\n", conclusionPos);
        step.conclusions.push_back(generated.substr(conclusionPos + 11, endPos - conclusionPos - 11));
    }
    
    // Gather evidence
    auto evidenceResult = gatherSupportingEvidence(step, chain);
    if (evidenceResult) {
        step.supportingEvidence = evidenceResult.value();
    }
    
    // Check for counter evidence
    auto counterResult = gatherCounterEvidence(step, chain);
    if (counterResult) {
        step.counterEvidence = counterResult.value();
    }
    
    // Adjust confidence based on evidence
    float evidenceWeight = 0.0f;
    for (const auto& evidence : step.supportingEvidence) {
        evidenceWeight += calculateEvidenceWeight(evidence);
    }
    
    float contradictionPenalty = calculateContradictionPenalty(step.counterEvidence);
    
    step.confidence = std::max(0.1f, std::min(1.0f, 
        step.confidence + evidenceWeight - contradictionPenalty));
    
    return step;
}

std::expected<bool, ChainError> ChainOfThought::validateStep(
    const ThoughtStep& step,
    const ReasoningChain& chain
) {
    // Real logical validation
    auto consistencyResult = checkLogicalConsistency(step, chain);
    if (!consistencyResult) {
        return std::unexpected(consistencyResult.error());
    }
    
    if (!consistencyResult.value()) {
        return false;
    }
    
    // Check for contradictions
    auto contradictionResult = identifyContradictions(chain);
    if (!contradictionResult) {
        return std::unexpected(contradictionResult.error());
    }
    
    auto contradictions = contradictionResult.value();
    for (const auto& contradiction : contradictions) {
        if (step.content.find(contradiction) != std::string::npos) {
            spdlog::warn("Step {} contradicts previous reasoning: {}", 
                        step.id, contradiction);
            return false;
        }
    }
    
    // Check for circular reasoning
    auto circularResult = identifyCircularReasoning(chain);
    if (!circularResult) {
        return std::unexpected(circularResult.error());
    }
    
    auto circular = circularResult.value();
    for (const auto& circle : circular) {
        if (step.content.find(circle) != std::string::npos) {
            spdlog::warn("Step {} introduces circular reasoning: {}", 
                        step.id, circle);
            return false;
        }
    }
    
    // Validate evidence
    for (const auto& evidence : step.supportingEvidence) {
        auto evidenceValid = evaluateEvidence(evidence, chain);
        if (!evidenceValid || evidenceValid.value() < 0.5f) {
            spdlog::warn("Weak evidence in step {}: {}", step.id, evidence);
            return false;
        }
    }
    
    return true;
}

std::expected<ReasoningChain, ChainError> ChainOfThought::backtrack(
    ReasoningChain& chain,
    size_t stepIndex
) {
    if (stepIndex >= chain.steps.size()) {
        return std::unexpected(ChainError::BacktrackingFailed);
    }
    
    // Remove steps from index onward
    chain.steps.resize(stepIndex);
    
    // Generate alternative step
    auto alternativeResult = generateNextStep(chain, chain.steps);
    if (!alternativeResult) {
        return std::unexpected(alternativeResult.error());
    }
    
    auto& alternativeStep = alternativeResult.value();
    alternativeStep.isRevised = true;
    alternativeStep.confidence *= 0.8f; // Lower confidence for revised steps
    alternativeStep.revisionCount = chain.steps.back().revisionCount + 1;
    
    chain.steps.push_back(alternativeStep);
    
    return chain;
}

std::expected<float, ChainError> ChainOfThought::calculateStepConfidence(
    const ThoughtStep& step,
    const ReasoningChain& chain
) {
    float confidence = step.confidence;
    
    // Weight by supporting evidence
    float evidenceWeight = 0.0f;
    for (const auto& evidence : step.supportingEvidence) {
        evidenceWeight += calculateEvidenceWeight(evidence);
    }
    
    // Penalty for counter evidence
    float contradictionPenalty = calculateContradictionPenalty(step.counterEvidence);
    
    // Bonus for being validated
    if (step.isValidated) {
        confidence += 0.1f;
    }
    
    // Penalty for being an assumption
    if (step.isAssumption) {
        confidence -= 0.2f;
    }
    
    // Penalty for multiple revisions
    confidence -= (step.revisionCount * 0.05f);
    
    return std::max(0.1f, std::min(1.0f, confidence + evidenceWeight - contradictionPenalty));
}

std::expected<std::string, ChainError> ChainOfThought::generateExplanation(
    const ReasoningChain& chain
) {
    std::string explanation = std::format(
        "Reasoning for: {}\n"
        "Overall confidence: {:.2f}\n"
        "Steps: {}\n"
        "Unresolved questions: {}\n"
        "Contradictions: {}\n\n",
        chain.goal,
        chain.overallConfidence,
        chain.steps.size(),
        chain.unresolvedQuestions.size(),
        chain.contradictions.size()
    );
    
    explanation += "Reasoning Trace:\n";
    explanation += "================\n\n";
    
    for (size_t i = 0; i < chain.steps.size(); ++i) {
        const auto& step = chain.steps[i];
        
        explanation += std::format(
            "Step {} (confidence: {:.2f}):\n"
            "  Content: {}\n"
            "  Reasoning: {}\n",
            i + 1,
            step.confidence,
            step.content,
            step.reasoning
        );
        
        if (!step.premises.empty()) {
            explanation += "  Premises:\n";
            for (const auto& premise : step.premises) {
                explanation += std::format("    - {}\n", premise);
            }
        }
        
        if (!step.conclusions.empty()) {
            explanation += "  Conclusions:\n";
            for (const auto& conclusion : step.conclusions) {
                explanation += std::format("    - {}\n", conclusion);
            }
        }
        
        if (!step.supportingEvidence.empty()) {
            explanation += "  Supporting Evidence:\n";
            for (const auto& evidence : step.supportingEvidence) {
                explanation += std::format("    - {}\n", evidence);
            }
        }
        
        if (!step.counterEvidence.empty()) {
            explanation += "  Counter Evidence:\n";
            for (const auto& evidence : step.counterEvidence) {
                explanation += std::format("    - {}\n", evidence);
            }
        }
        
        if (step.isAssumption) {
            explanation += "  [ASSUMPTION]\n";
        }
        
        if (step.isRevised) {
            explanation += "  [REVISED]\n";
        }
        
        if (!step.isValidated) {
            explanation += "  [UNVALIDATED]\n";
        }
        
        explanation += "\n";
    }
    
    if (!chain.unresolvedQuestions.empty()) {
        explanation += "Unresolved Questions:\n";
        for (const auto& question : chain.unresolvedQuestions) {
            explanation += std::format("  - {}\n", question);
        }
        explanation += "\n";
    }
    
    if (!chain.contradictions.empty()) {
        explanation += "Contradictions:\n";
        for (const auto& contradiction : chain.contradictions) {
            explanation += std::format("  - {}\n", contradiction);
        }
        explanation += "\n";
    }
    
    return explanation;
}

std::expected<std::string, ChainError> ChainOfThought::visualizeChain(
    const ReasoningChain& chain,
    const std::string& format
) {
    if (format == "json") {
        json visualization;
        visualization["goal"] = chain.goal;
        visualization["confidence"] = chain.overallConfidence;
        visualization["steps"] = json::array();
        
        for (size_t i = 0; i < chain.steps.size(); ++i) {
            const auto& step = chain.steps[i];
            visualization["steps"].push_back({
                {"id", step.id},
                {"content", step.content},
                {"confidence", step.confidence},
                {"validated", step.isValidated},
                {"assumption", step.isAssumption},
                {"revised", step.isRevised},
                {"premises", step.premises},
                {"conclusions", step.conclusions},
                {"supporting_evidence", step.supportingEvidence},
                {"counter_evidence", step.counterEvidence}
            });
        }
        
        return visualization.dump(2);
    } else if (format == "graphviz") {
        std::string dot = "digraph ReasoningChain {\n";
        dot += "  rankdir=TB;\n";
        dot += "  node [shape=box, style=rounded];\n\n";
        
        // Add nodes
        for (size_t i = 0; i < chain.steps.size(); ++i) {
            const auto& step = chain.steps[i];
            dot += std::format("  {} [label=\"{}\\n(conf: {:.2f})\"",
                             step.id, step.content, step.confidence);
            
            if (step.isAssumption) {
                dot += ", style=dashed";
            }
            if (!step.isValidated) {
                dot += ", color=red";
            }
            if (step.isRevised) {
                dot += ", color=orange";
            }
            
            dot += "];\n";
        }
        
        // Add edges
        for (size_t i = 1; i < chain.steps.size(); ++i) {
            dot += std::format("  {} -> {};\n", 
                             chain.steps[i-1].id, chain.steps[i].id);
        }
        
        dot += "}\n";
        return dot;
    }
    
    return std::unexpected(ChainError::InvalidFormat);
}

std::string ChainOfThought::generateStepId() {
    static std::atomic<uint64_t> counter{0};
    return "step_" + std::to_string(counter.fetch_add(1));
}

float ChainOfThought::calculateEvidenceWeight(const std::string& evidence) {
    // Real evidence weighting based on source reliability
    float weight = 0.5f; // Base weight
    
    // Boost for strong evidence
    if (evidence.find("empirical") != std::string::npos) weight += 0.3f;
    if (evidence.find("experimental") != std::string::npos) weight += 0.3f;
    if (evidence.find("theoretical") != std::string::npos) weight += 0.2f;
    if (evidence.find("observed") != std::string::npos) weight += 0.2f;
    if (evidence.find("measured") != std::string::npos) weight += 0.2f;
    
    // Penalty for weak evidence
    if (evidence.find("assumed") != std::string::npos) weight -= 0.2f;
    if (evidence.find("speculated") != std::string::npos) weight -= 0.3f;
    if (evidence.find("hypothesized") != std::string::npos) weight -= 0.1f;
    
    return std::max(0.0f, std::min(1.0f, weight));
}

float ChainOfThought::calculateContradictionPenalty(
    const std::vector<std::string>& contradictions
) {
    float penalty = 0.0f;
    
    for (const auto& contradiction : contradictions) {
        // Major contradictions have higher penalty
        if (contradiction.find("contradicts") != std::string::npos) {
            penalty += 0.3f;
        } else if (contradiction.find("conflicts") != std::string::npos) {
            penalty += 0.2f;
        } else if (contradiction.find("inconsistent") != std::string::npos) {
            penalty += 0.15f;
        } else {
            penalty += 0.1f; // Minor contradiction
        }
    }
    
    return std::min(1.0f, penalty);
}

