void TokenGenerator::initialize() {
    std::lock_guard lock(m_mutex);
    
    if (m_initialized.load()) {
        return;
    }
    
    spdlog::info("Initializing TokenGenerator with {} strategy", 
                static_cast<int>(m_config.strategy));
    
    // Load special tokens
    m_vocab["<pad>"] = {m_padToken, "<pad>", 1.0f, "special", 0};
    m_vocab["<s>"] = {m_bosToken, "<s>", 1.0f, "special", 0};
    m_vocab["</s>"] = {m_eosToken, "</s>", 1.0f, "special", 0};
    m_vocab["<unk>"] = {m_unkToken, "<unk>", 1.0f, "special", 0};
    m_vocab["<mask>"] = {m_maskToken, "<mask>", 1.0f, "special", 0};
    
    // Load vocabulary if path provided
    if (!m_config.vocabPath.empty()) {
        auto result = loadVocabulary(m_config.vocabPath);
        if (!result) {
            spdlog::warn("Failed to load vocabulary from {}, creating minimal vocabulary", 
                        m_config.vocabPath);
            createMinimalVocabulary();
        } else {
            spdlog::info("Loaded vocabulary from {}", m_config.vocabPath);
        }
    } else {
        createMinimalVocabulary();
    }
    
    // Load merge rules if path provided
    if (!m_config.mergesPath.empty()) {
        auto result = loadMergeRules(m_config.mergesPath);
        if (!result) {
            spdlog::warn("Failed to load merge rules from {}", m_config.mergesPath);
        } else {
            spdlog::info("Loaded merge rules from {}", m_config.mergesPath);
        }
    }
    
    // Load from model if path provided
    if (!m_config.modelPath.empty()) {
        auto result = loadVocabularyFromModel(m_config.modelPath);
        if (!result) {
            spdlog::warn("Failed to load vocabulary from model {}", m_config.modelPath);
        }
    }
    
    // Initialize GPU backend if enabled
    if (m_config.enableGPUPipeline) {
        auto gpuResult = initializeGPUBackend();
        if (!gpuResult) {
            spdlog::warn("Failed to initialize GPU backend, falling back to CPU");
            m_config.backend = TokenizationBackend::CPU;
        } else {
            spdlog::info("GPU backend initialized successfully");
        }
    }
    
    // Build reverse mapping
    for (const auto& [token, info] : m_vocab) {
        m_idToToken[info.id] = info;
    }
    
    m_initialized = true;
    spdlog::info("TokenGenerator initialized with {} tokens", m_vocab.size());
}

std::expected<std::vector<int>, TokenError> TokenGenerator::encode(const std::string& text) {
    if (!m_initialized.load()) {
        return std::unexpected(TokenError::TokenizationFailed);
    }
    
    if (text.empty()) {
        return std::vector<int>();
    }
    
    // Check cache first
    if (m_config.enableCache) {
        auto cacheResult = getFromCache(text, true);
        if (cacheResult) {
            m_cacheHits.fetch_add(1);
            return cacheResult.value();
        }
        m_cacheMisses.fetch_add(1);
    }
    
    auto startTime = std::chrono::steady_clock::now();
    
    // Normalize input
    std::string normalized = text;
    if (m_config.handleUnicode) {
        auto normResult = normalizeUnicode(text);
        if (normResult) {
            normalized = normResult.value();
        }
    }
    
    if (m_config.addPrefixSpace && !normalized.empty() && normalized[0] != ' ') {
        normalized = " " + normalized;
    }
    
    // Use GPU backend if available and enabled
    if (m_config.backend == TokenizationBackend::GPU && m_gpuBackendInitialized.load()) {
        auto gpuResult = encodeGPU(normalized);
        if (gpuResult) {
            // Cache result
            if (m_config.enableCache) {
                addToCache(text, gpuResult.value(), true);
            }
            
            auto endTime = std::chrono::steady_clock::now();
            auto duration = std::chrono::duration_cast<std::chrono::nanoseconds>(endTime - startTime);
            recordPerformanceMetrics("encode_gpu", duration, gpuResult->size());
            
            logTokenization(text, gpuResult.value());
            return gpuResult;
        }
        // Fallback to CPU on GPU failure
        spdlog::warn("GPU encoding failed, falling back to CPU");
    }
    
    // CPU encoding based on strategy
    std::vector<int> tokens;
    TokenError error = TokenError::Success;
    
    switch (m_config.strategy) {
        case TokenizationStrategy::BPE:
            {
                auto result = bpeEncode(normalized);
                if (!result) {
                    return std::unexpected(result.error());
                }
                tokens = result.value();
            }
            break;
            
        case TokenizationStrategy::WordPiece:
            {
                auto result = wordpieceEncode(normalized);
                if (!result) {
                    return std::unexpected(result.error());
                }
                tokens = result.value();
            }
            break;
            
        case TokenizationStrategy::SentencePiece:
            {
                auto result = sentencepieceEncode(normalized);
                if (!result) {
                    return std::unexpected(result.error());
                }
                tokens = result.value();
            }
            break;
            
        case TokenizationStrategy::Unigram:
            {
                // Fallback to BPE for unigram
                auto result = bpeEncode(normalized);
                if (!result) {
                    return std::unexpected(result.error());
                }
                tokens = result.value();
            }
            break;
    }
    
    // Add special tokens if configured
    if (m_config.addSpecialTokens) {
        tokens.insert(tokens.begin(), m_bosToken);
        tokens.push_back(m_eosToken);
    }
    
    // Cache result
    if (m_config.enableCache) {
        addToCache(text, tokens, true);
    }
    
    auto endTime = std::chrono::steady_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::nanoseconds>(endTime - startTime);
    recordPerformanceMetrics("encode_cpu", duration, tokens.size());
    
    logTokenization(text, tokens);
    
    return tokens;
}

