void TokenGenerator::recordPerformanceMetrics(
    const std::string& operation,
    std::chrono::nanoseconds duration,
    size_t tokensProcessed
) {
    if (operation.find("encode") != std::string::npos) {
        m_totalEncodingTime.fetch_add(duration);
        m_totalEncodings.fetch_add(1);
    } else if (operation.find("decode") != std::string::npos) {
        m_totalDecodingTime.fetch_add(duration);
        m_totalDecodings.fetch_add(1);
    }
    
    m_totalTokensProcessed.fetch_add(tokensProcessed);
    
    // Calculate throughput
    double throughput = static_cast<double>(tokensProcessed) / duration.count() * 1e9;
    spdlog::debug("Tokenization {} throughput: {:.2f} tokens/sec", 
                operation, throughput);
}

json TokenGenerator::getPerformanceMetrics() const {
    auto encodingTime = m_totalEncodingTime.load();
    auto decodingTime = m_totalDecodingTime.load();
    
    double encodeThroughput = 0.0;
    double decodeThroughput = 0.0;
    
    if (encodingTime.count() > 0) {
        encodeThroughput = static_cast<double>(m_totalTokensProcessed.load()) / 
                          encodingTime.count() * 1e9;
    }
    
    if (decodingTime.count() > 0) {
        decodeThroughput = static_cast<double>(m_totalTokensProcessed.load()) / 
                          decodingTime.count() * 1e9;
    }
    
    return {
        {"total_encodings", m_totalEncodings.load()},
        {"total_decodings", m_totalDecodings.load()},
        {"total_tokens_processed", m_totalTokensProcessed.load()},
        {"cache_hits", m_cacheHits.load()},
        {"cache_misses", m_cacheMisses.load()},
        {"cache_size", m_cacheSize.load()},
        {"vocab_size", m_vocab.size()},
        {"merge_rules_size", m_mergeRules.size()},
        {"encode_throughput", encodeThroughput},
        {"decode_throughput", decodeThroughput},
        {"gpu_backend_initialized", m_gpuBackendInitialized.load()}
    };
